// Vulnerable
const query = `SELECT * FROM users WHERE email = '${userInput}'`;

// Safe with parameterized query
const query = db.select().from(users).where(eq(users.email, userInput));

// Dangerous: rendering user input directly
<div dangerouslySetInnerHTML={{ __html: userComment }} />

// Safe: escape HTML entities
<div>{userComment}</div>

// Express cookie with SameSite protection
res.cookie('session', token, {
  httpOnly: true,
  secure: true,
  sameSite: 'strict',
  maxAge: 3600000
});

import bcrypt from 'bcrypt';

// Hash with cost factor 12
const hash = await bcrypt.hash(password, 12);

// Verify
const isValid = await bcrypt.compare(password, hash);

// Node.js TLS pinning example
const https = require('https');
const options = {
  hostname: 'api.example.com',
  fingerprint: 'SHA256:AB:CD:EF:...',
  checkServerIdentity: (host, cert) => {
    if (cert.fingerprint256 !== options.fingerprint) {
      return new Error('Certificate pinning failure');
    }
  }
};
